query:
-- Delete all but the newest document for each duplicate title
DELETE FROM secure_documents 
WHERE id NOT IN (
  SELECT keep_id FROM (
    SELECT MAX(id) as keep_id 
    FROM secure_documents 
    GROUP BY title
  ) as keepers
);

